Here's a modern MSTest test class for your `DataFetcher`, covering success, failure, cancellation, and timeout scenarios:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode statusCode = HttpStatusCode.OK,
        string content = "response-body")
    {
        var handler = new FakeHandler(statusCode, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/error", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var (fetcher, handler) = CreateFetcher();
        handler.SimulateDelay = TimeSpan.FromSeconds(30);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledCooperatively()
    {
        // [Timeout] triggers TestContext.CancellationToken, which propagates
        // to the handler via the token passed to FetchAsync.
        var (fetcher, handler) = CreateFetcher();
        handler.SimulateDelay = TimeSpan.FromSeconds(60);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/hang", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesUrlToHttpClient()
    {
        var (fetcher, handler) = CreateFetcher();

        await fetcher.FetchAsync(
            "https://example.com/specific-path", _testContext.CancellationToken);

        Assert.AreEqual(
            new Uri("https://example.com/specific-path"), handler.LastRequestUri);
    }

    /// <summary>
    /// Fake handler that returns a canned response and optionally delays.
    /// </summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        private readonly string _content;

        public TimeSpan SimulateDelay { get; set; }
        public Uri? LastRequestUri { get; private set; }

        public FakeHandler(HttpStatusCode statusCode, string content = "")
        {
            _statusCode = statusCode;
            _content = content;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            LastRequestUri = request.RequestUri;

            if (SimulateDelay > TimeSpan.Zero)
            {
                await Task.Delay(SimulateDelay, cancellationToken);
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

- **`TestContext.CancellationToken`** — passed through to `FetchAsync` so `[Timeout]` cancels cooperatively instead of thread-aborting
- **`Assert.ThrowsExactlyAsync`** — verifies the exact exception type (not `[ExpectedException]`)
- **`FakeHandler`** — subclasses `HttpMessageHandler` to control `HttpClient` without mocking frameworks
- **`sealed` test class** — MSTest best practice for performance
- **Constructor-injected `TestContext`** — avoids nullable property pattern

The timeout test (`TimeoutExpires_IsCancelledCooperatively`) demonstrates how `[Timeout(3000)]` fires `TestContext.CancellationToken` after 3 seconds, which propagates through your `FetchAsync` call and raises `TaskCanceledException` — proving your code handles cooperative cancellation correctly.
